function AppConfirmDialog({
  onResolve,
  request,
}: {
  onResolve: (confirmed: boolean) => void;
  request: AppDialogRequest | null;
}) {
  const cancelButtonRef = useRef<HTMLButtonElement | null>(null);
  const confirmButtonRef = useRef<HTMLButtonElement | null>(null);
  useEscapeLayer(Boolean(request), () => onResolve(false), ESCAPE_PRIORITY_DIALOG);
  useEffect(() => {
    if (!request) return;
    window.requestAnimationFrame(() => {
      confirmButtonRef.current?.focus();
    });
  }, [request]);

  const dialog = request
    ? (() => {
        const handleDialogKeyDown = (event: ReactKeyboardEvent<HTMLFormElement>) => {
          if (event.key !== "Enter" || event.altKey || event.ctrlKey || event.metaKey || event.shiftKey || event.nativeEvent.isComposing) return;
          event.preventDefault();
          event.stopPropagation();
          onResolve(true);
        };

        const tone = request.tone || "default";
        const titleId = `app-confirm-title-${request.id}`;
        const confirmLabel = request.confirmLabel || "OK";
        const cancelLabel = request.cancelLabel || "Cancel";
        const icon =
          tone === "danger" ? (
            <AlertTriangle size={18} />
          ) : tone === "warning" ? (
            <Info size={18} />
          ) : request.mode === "alert" ? (
            <Info size={18} />
          ) : (
            <CheckCircle2 size={18} />
          );
        return (
          <m.div
            key={request.id}
            className="confirm-backdrop"
            data-escape-layer="dialog"
            role="presentation"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onMouseDown={(event) => {
              if (event.target === event.currentTarget) onResolve(false);
            }}
          >
            <m.form
              className={`confirm-dialog app-confirm-dialog ${tone}`}
              role="alertdialog"
              aria-modal="true"
              aria-labelledby={titleId}
              initial={{ opacity: 0, scale: 0.985, y: 8 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.985, y: 8 }}
              transition={{ duration: 0.16, ease: "easeOut" }}
              onKeyDownCapture={handleDialogKeyDown}
              onSubmit={(event) => {
                event.preventDefault();
                onResolve(true);
              }}
            >
              <div className="confirm-dialog-heading">
                <div>
                  <span>{request.eyebrow || (request.mode === "alert" ? "Notice" : "Confirmation")}</span>
                  <h2 id={titleId}>{request.title}</h2>
                </div>
                <i className={`confirm-dialog-icon ${tone}`} aria-hidden="true">
                  {icon}
                </i>
              </div>
              <AppDialogMessage message={request.message} />
              <div className="confirm-dialog-actions">
                {request.mode === "confirm" ? (
                  <MotionActionButton ref={cancelButtonRef} className="secondary-button" type="button" onClick={() => onResolve(false)}>
                    <X size={16} />
                    {cancelLabel}
                  </MotionActionButton>
                ) : null}
                <MotionActionButton ref={confirmButtonRef} className={`primary-button${tone === "danger" ? " danger" : ""}`} type="submit">
                  {tone === "danger" ? <AlertTriangle size={16} /> : <CheckCircle2 size={16} />}
                  {confirmLabel}
                </MotionActionButton>
              </div>
            </m.form>
          </m.div>
        );
      })()
    : null;
  return createPortal(<AnimatePresence>{dialog}</AnimatePresence>, document.body);
}

function useAppDialogController() {
  const [request, setRequest] = useState<AppDialogRequest | null>(null);
  const nextRequestIdRef = useRef(0);
  const resolverRef = useRef<((confirmed: boolean) => void) | null>(null);
  const resolveDialog = useCallback((confirmed: boolean) => {
    const resolver = resolverRef.current;
    resolverRef.current = null;
    setRequest(null);
    if (resolver) resolver(confirmed);
  }, []);
  const confirm = useCallback<ShowAppConfirmDialog>((options) => {
    if (resolverRef.current) resolverRef.current(false);
    return new Promise<boolean>((resolve) => {
      resolverRef.current = resolve;
      setRequest({ ...options, id: ++nextRequestIdRef.current, mode: "confirm" });
    });
  }, []);
  const alert = useCallback<ShowAppAlertDialog>((options) => {
    if (resolverRef.current) resolverRef.current(false);
    return new Promise<void>((resolve) => {
      resolverRef.current = () => resolve();
      setRequest({ ...options, id: ++nextRequestIdRef.current, mode: "alert" });
    });
  }, []);
  useEffect(
    () => () => {
      if (resolverRef.current) resolverRef.current(false);
    },
    [],
  );
  const node = <AppConfirmDialog request={request} onResolve={resolveDialog} />;
  return { alert, confirm, node };
}

function parseLibraryPageSize(value: string | null): LibraryPageSize {
  const numericValue = Number(value);
  return Number.isInteger(numericValue) && numericValue >= MIN_LIBRARY_PAGE_SIZE ? numericValue : DEFAULT_LIBRARY_PAGE_SIZE;
}

function readStoredLibraryPageSize(): LibraryPageSize {
  return parseLibraryPageSize(localStorage.getItem(LIBRARY_PAGE_SIZE_STORAGE_KEY));
}

function writeStoredLibraryPageSize(value: LibraryPageSize) {
  localStorage.setItem(LIBRARY_PAGE_SIZE_STORAGE_KEY, String(value));
}

function normalizeLibraryDensity(value?: string | null): LibraryDensity {
  return LIBRARY_DENSITY_OPTIONS.some((option) => option.value === value) ? (value as LibraryDensity) : DEFAULT_LIBRARY_DENSITY;
}

function libraryPreviewCapacityForViewport(width: number, height: number): LibraryPreviewCapacity {
  if (width >= LIBRARY_PREVIEW_CAPACITY_EXPANSIVE_WIDTH && height >= LIBRARY_PREVIEW_CAPACITY_EXPANSIVE_HEIGHT) {
    return "expansive";
  }
  if (width >= LIBRARY_PREVIEW_CAPACITY_STANDARD_WIDTH && height >= LIBRARY_PREVIEW_CAPACITY_STANDARD_HEIGHT) {
    return "roomy";
  }
  return "standard";
}

function normalizeDetailStickyFields(value?: string[] | null): DetailStickyField[] {
  const valid = new Set(DETAIL_STICKY_FIELD_OPTIONS.map((option) => option.value));
  const fields = (value || [])
    .map((item) => String(item || "").trim().toLowerCase())
    .filter((item): item is DetailStickyField => valid.has(item as DetailStickyField));
  const unique = Array.from(new Set(fields));
  return unique.length ? unique : DEFAULT_DETAIL_STICKY_FIELDS;
}

